const body = $input.first().json.body || $input.first().json || {};
const apiUrl = $env.N3_API_URL || '{{$env.GATEWAY_URL}}';
const secret = $env.N8N_INTERNAL_SECRET;
if (!secret) return [{ json: { error: true, message: 'N8N_INTERNAL_SECRET未設定', code: 'CONFIG_ERROR' } }];
const snapshotDate = body.date || new Date().toISOString().split('T')[0];
const isScheduled = !$input.first().json.body;
return [{ json: { snapshot_date: snapshotDate, is_scheduled: isScheduled, api_url: apiUrl } }];

const config = $node['🔐 初期化'].json;
const sales = $node['📊 売上統計取得'].json || {};
const inventory = $node['📦 在庫統計取得'].json || {};
const tasks = $node['📋 タスク統計取得'].json || {};
const listings = $node['🏷️ 出品統計取得'].json || {};
const snapshot = {
  snapshot_date: config.snapshot_date,
  sales: {
    total_orders: parseInt(sales.total_orders) || 0,
    total_revenue: parseFloat(sales.total_revenue) || 0,
    shipped_orders: parseInt(sales.shipped_orders) || 0,
    pending_orders: parseInt(sales.pending_orders) || 0
  },
  inventory: {
    total_products: parseInt(inventory.total_products) || 0,
    out_of_stock: parseInt(inventory.out_of_stock) || 0,
    low_stock: parseInt(inventory.low_stock) || 0,
    inventory_value: parseFloat(inventory.inventory_value) || 0
  },
  tasks: {
    total_tasks: parseInt(tasks.total_tasks) || 0,
    high_priority: parseInt(tasks.high_priority) || 0,
    pending_tasks: parseInt(tasks.pending_tasks) || 0,
    inquiry_count: parseInt(tasks.inquiry_count) || 0
  },
  listings: {
    total_listed: parseInt(listings.total_listed) || 0,
    active_listings: parseInt(listings.active_listings) || 0,
    avg_margin: parseFloat(listings.avg_margin) || 0
  }
};
return [{ json: snapshot }];

// N3 HMAC署名検証（要塞化自動挿入）
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || $input.first().json;

const signature = headers['x-n3-signature'] || headers['X-N3-Signature'] || '';
const timestamp = headers['x-n3-timestamp'] || headers['X-N3-Timestamp'] || '';

if (signature && timestamp) {
  const secret = $env.N3_HMAC_SECRET;
  if (!secret) {
    return [{ json: { error: true, message: 'N3_HMAC_SECRET 環境変数が未設定', code: 'CONFIG_ERROR' } }];
  }

  const ts = parseInt(timestamp, 10);
  const now = Math.floor(Date.now() / 1000);
  if (Math.abs(now - ts) > 300) {
    return [{ json: { error: true, message: 'タイムスタンプ期限切れ', code: 'TIMESTAMP_EXPIRED' } }];
  }

  try {
    const verifyUrl = $env.PRICING_ENGINE_URL || 'http://localhost:8000';
    const payload = JSON.stringify(body);
    const response = await fetch(`${verifyUrl}/verify-signature`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ payload, signature, timestamp })
    });
    const result = await response.json();
    if (!result.valid) {
      return [{ json: { error: true, message: '署名検証失敗: ' + (result.error || ''), code: 'INVALID_SIGNATURE' } }];
    }
  } catch (e) {
    console.log('署名検証スキップ: ' + e.message);
  }
}

return $input.all();
